																	id="phone_number" name="phone_number"
																	pattern="^\d{10}$"
																	oninput="this.value = this.value.replace(/[^0-9]/g, '')"
																	maxlength="10" placeholder="Nhập số điện thoại"
																	required=""></label>
														</div>
														<div class="item item-full">
															<label for="full_address">Địa chỉ</label>
