	<script>
		(function (d, t) {
			const CONFIG = {
				BASE_URL: "https://erp.nvbplay.vn",
				WEBSITE_TOKEN: "AmMAheUb69x3QB7gHf1mFaki"
			};
			let chatwootLoaded = false;

			function loadChatwoot() {
				if (chatwootLoaded) return;
				chatwootLoaded = true;

				const script = d.createElement("script");
				script.src = `${CONFIG.BASE_URL}/packs/js/sdk.js`;
				script.defer = script.async = true;
				d.head.appendChild(script);

				script.onload = () => {
					window.chatwootSDK.run({
						websiteToken: CONFIG.WEBSITE_TOKEN,
						baseUrl: CONFIG.BASE_URL
					});

					window.addEventListener("chatwoot:ready", setupUser);
				};
			}

			function setupUser() {
				const user = { "identifier": "guest_user", "name": "Guest" };

				if (user.email) {
					window.$chatwoot.setUser(user.email, user);
					console.log("User identified and sent to Chatwoot.");
				}
			}

			window.addEventListener("scroll", () => {
				if (window.scrollY > 100) loadChatwoot();
			}, {
				passive: true
			});
		})(document, "script");

		function sendChatwootMessage(content, label, cwConversationValue) {
			const CONFIG = {
				BASE_URL: "https://erp.nvbplay.vn",
				WEBSITE_TOKEN: "AmMAheUb69x3QB7gHf1mFaki"
			};
			window.$chatwoot.toggle("open");
			window.$chatwoot.setLabel(label);
			jQuery.ajax({
				url: `${CONFIG.BASE_URL}/api/v1/widget/messages`,
				type: "POST",
				data: JSON.stringify({
					message: {
						content,
						reply_to: null,
						referer_url: "https://nvbplay.vn/"
					}
				}),
				headers: {
					"x-auth-token": cwConversationValue,
					"Content-Type": "application/json"
				},
				dataType: "json",
				data: {
					website_token: CONFIG.WEBSITE_TOKEN,
					cw_conversation: cwConversationValue,
					locale: "vi"
				}
			}).then(
				res => console.log(res),
				err => console.error("Error:", err)
			);
		}
		window.addEventListener('chatwoot:ready', () => {
			var iframe = document.getElementById("chatwoot_live_chat_widget"),
				iframeSrc = iframe.src,
				urlObj = new URL(iframeSrc),
				cwConversationValue = urlObj.searchParams.get("cw_conversation");
			jQuery(document).on('click', '.send-product-info', function () {
				const productName = jQuery("h1.product_title").text().trim(),
					productUrl = jQuery(location).attr('href'),
					productPrice = jQuery(".entry-summary .woocommerce-Price-amount bdi").text().trim(),
					messageContent = `Xin chào, tôi muốn liên hệ về sản phẩm: \nTên: ${productName}\nGiá: ${productPrice}\nTại: ${productUrl}`;
				sendChatwootMessage(messageContent, "Liên hệ về Sản phẩm"), cwConversationValue;
			});

			jQuery(document).on('click', '.course-list .button', function () {
				const courseName = jQuery(this).closest('.stack').find('.stadium-card-title p').text().trim(),
					messageContent = `${courseName}`;
				// alert(messageContent);
				sendChatwootMessage(messageContent, "Đăng ký hóa học", cwConversationValue);
			});


			jQuery(document).on('click', '.grid-stadium-list .button.btn-accept', function () {
				const stadiumName = jQuery(this).closest('.stadium-card-body').find('.stadium-card-name h3').text().trim(),
					messageContent = `${stadiumName}`;
				// alert(messageContent);
				sendChatwootMessage(messageContent, "Đặt sân", cwConversationValue);
			});

		});

		['chatwoot:on-message', 'chatwoot:opened', 'chatwoot:closed'].forEach(event => {
			window.addEventListener(event, (e) => console.log(`${event} event:`, e.detail || 'Triggered'));
		});

		jQuery(document).ready(function ($) {
			var params = new URLSearchParams(window.location.search);
			var conditions = [
				function () {
					return ["coupon", "Viewparty"].includes(params.get("utm_content"));
				},
				function () {
					return params.get("utm_source") === 'QRPanoQC' && params.get("utm_id") === 'QRPano' && params.get("utm_medium") === 'PhanvantriPhongdien';
				},
				function () {
					return params.get("utm_source") === 'QRPanoQC' && params.get("utm_medium") === 'HoangLongTHN';
				},
				function () {
					return params.get("utm_source") === 'Voucher50k' && params.get("utm_campaign") === 'ScanQR';
				},
				function () {
					return params.get("utm_source") === 'ViewPartyCKTG24' && params.get("utm_campaign") === 'ScanQRViewParty';
				},
				function () {
					return params.get("utm_source") === 'Voucher50kSancaulong586' && params.get("utm_campaign") === 'Voucher50kSancaulong586';
				},
				function () {
					return params.get("utm_source") === 'Voucher50kSan79TranPhu' && params.get("utm_campaign") === 'Voucher50kSan79TranPhu';
				},
				function () {
					return params.get("utm_source") === 'Voucher50kPickleball448CR' && params.get("utm_campaign") === 'Voucher50kPickleball448CR';
				},
				function () {
					return params.get("utm_source") === 'Voucher50kBMT71TranPhu' && params.get("utm_campaign") === 'Voucher50kBMT71TranPhu';
				},
				function () {
					return params.get("utm_source") === 'VoucherVC50kHopLucNK' && params.get("utm_campaign") === 'VoucherVC50kHopLucNK';
				},
				function () {
					return params.get("utm_source") === 'VoucherVC50kLeBinhCR' && params.get("utm_campaign") === 'VoucherVC50kLeBinhCR';
				},
				function () {
					return params.get("utm_source") === 'Voucher50KMSonLam' && params.get("utm_campaign") === 'Voucher50KMSonLam';
				}
			];
			if (conditions.some(function (check) {
				return check();
			})) {
				setTimeout(function () {
					$.loadMagnificPopup().then(() => {
						$.magnificPopup.open({
							mainClass: "home-qr-code-control",
							items: {
								src: '#voucher-50k'
							},
							type: 'inline'
						})
					})
				}, 1500);
			}
		});
	</script>
